customCss:
@import url('https://fonts.googleapis.com/css2?family=Rajdhani:wght@400;500;600;700&family=Share+Tech+Mono&display=swap');
:root { --font-body: 'Rajdhani', sans-serif; --font-display: 'Share Tech Mono', monospace; --radius: 2px; --ambient-glow-opacity: 0.22; }

/* ── Scanlines over hero ── */
.home-hero::after { content: ''; position: absolute; inset: 0; background: repeating-linear-gradient(0deg, transparent, transparent 2px, rgba(0,0,0,0.12) 2px, rgba(0,0,0,0.12) 4px); pointer-events: none; z-index: 5; mix-blend-mode: multiply; }

/* ── Neon glow borders on cards ── */
.media-card-image { border: 1px solid rgba(255,45,111,0.25); transition: border-color 0.3s, box-shadow 0.3s; }
.media-card:hover .media-card-image { border-color: #00f0ff; box-shadow: 0 0 12px rgba(0,240,255,0.4), 0 0 30px rgba(0,240,255,0.15), inset 0 0 12px rgba(0,240,255,0.08); }
.media-card:hover { transform: translateY(-4px); filter: brightness(1.15); }

/* ── Glowing sidebar edge ── */
aside { border-right: 1px solid rgba(255,45,111,0.3) !important; box-shadow: 1px 0 20px rgba(255,45,111,0.12); }
.sidebar-logo-icon { border: 1px solid rgba(0,240,255,0.4); box-shadow: 0 0 8px rgba(0,240,255,0.3); }

/* ── Section headers: uppercase tech style ── */
.section-header { text-transform: uppercase; letter-spacing: 0.18em; font-family: 'Share Tech Mono', monospace; font-size: 0.7rem; }

/* ── Badges with neon border ── */
.metadata-badge { border: 1px solid rgba(0,240,255,0.3); text-shadow: 0 0 6px rgba(0,240,255,0.5); letter-spacing: 0.08em; }

/* ── Glass panels: more angular, colored tint ── */
.glass, .glass-subtle, .glass-dark { border: 1px solid rgba(255,45,111,0.15); }

/* ── Pill buttons: sharp + neon ── */
.pill-primary { box-shadow: 0 0 12px rgba(255,45,111,0.4); }
.pill-primary:hover { box-shadow: 0 0 20px rgba(255,45,111,0.6), 0 0 40px rgba(255,45,111,0.2); }

/* ── Surface panels get subtle edge glow ── */
.surface-panel { border: 1px solid rgba(0,240,255,0.1); }

/* ── Tab bar: underline style ── */
.tab-active { border-bottom: 2px solid #00f0ff; box-shadow: 0 2px 8px rgba(0,240,255,0.3); }

/* ── Page titles: monospace display ── */
.page-title { font-family: 'Share Tech Mono', monospace; text-transform: uppercase; letter-spacing: 0.05em; }

/* ── Progress bars: neon glow ── */
.progress-fill { box-shadow: 0 0 6px rgba(255,45,111,0.6); }
